{"path": "/root/clinica-duerksen-content/database/001_schema.sql", "content": "-- ============================================================================
-- Clinica Duerksen - Database Schema
-- Migration: 001_schema.sql
-- Description: Creates all tables, indexes, and constraints
-- Database: PostgreSQL (Supabase)
-- ============================================================================

-- Enable required extensions
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- ============================================================================
-- TABLE: services
-- Dental services offered by the clinic
-- ============================================================================
CREATE TABLE IF NOT EXISTS services (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    slug TEXT UNIQUE NOT NULL,
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    long_description TEXT,
    icon TEXT,
    image_url TEXT,
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE services IS 'Dental services offered by Clinica Duerksen';
COMMENT ON COLUMN services.slug IS 'URL-friendly identifier for the service';
COMMENT ON COLUMN services.icon IS 'Icon class name or SVG reference';
COMMENT ON COLUMN services.sort_order IS 'Display order (lower = first)';

CREATE INDEX idx_services_active_sort ON services (is_active, sort_order) WHERE is_active = true;
CREATE INDEX idx_services_slug ON services (slug);

-- ============================================================================
-- TABLE: team_members
-- Clinic staff and doctors
-- ============================================================================
CREATE TABLE IF NOT EXISTS team_members (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    title TEXT NOT NULL,
    bio TEXT,
    photo_url TEXT,
    credentials TEXT[] DEFAULT '{}',
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE team_members IS 'Doctors and staff at the clinic';
COMMENT ON COLUMN team_members.credentials IS 'Array of professional credentials and certifications';

CREATE INDEX idx_team_members_active_sort ON team_members (is_active, sort_order) WHERE is_active = true;

-- ============================================================================
-- TABLE: testimonials
-- Patient reviews and testimonials
-- ============================================================================
CREATE TABLE IF NOT EXISTS testimonials (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    patient_name TEXT NOT NULL,
    rating INTEGER NOT NULL CHECK (rating >= 1 AND rating <= 5),
    text TEXT NOT NULL,
    treatment_type TEXT,
    source TEXT NOT NULL DEFAULT 'website',
    is_featured BOOLEAN NOT NULL DEFAULT false,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE testimonials IS 'Patient testimonials and reviews';
COMMENT ON COLUMN testimonials.rating IS 'Star rating from 1 to 5';
COMMENT ON COLUMN testimonials.source IS 'Origin of review: website, google, facebook, etc.';

CREATE INDEX idx_testimonials_active ON testimonials (is_active) WHERE is_active = true;
CREATE INDEX idx_testimonials_featured ON testimonials (is_featured, is_active) WHERE is_featured = true AND is_active = true;

-- ============================================================================
-- TABLE: gallery_cases
-- Before/after treatment gallery
-- ============================================================================
CREATE TABLE IF NOT EXISTS gallery_cases (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title TEXT NOT NULL,
    description TEXT,
    before_image_url TEXT NOT NULL,
    after_image_url TEXT NOT NULL,
    treatment_type TEXT NOT NULL,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE gallery_cases IS 'Before/after treatment photo gallery';

CREATE INDEX idx_gallery_cases_active ON gallery_cases (is_active, created_at DESC) WHERE is_active = true;
CREATE INDEX idx_gallery_cases_treatment ON gallery_cases (treatment_type) WHERE is_active = true;

-- ============================================================================
-- TABLE: blog_posts
-- Blog articles and news
-- ============================================================================
CREATE TABLE IF NOT EXISTS blog_posts (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    slug TEXT UNIQUE NOT NULL,
    title TEXT NOT NULL,
    excerpt TEXT,
    content TEXT NOT NULL,
    cover_image_url TEXT,
    author_id UUID REFERENCES team_members(id) ON DELETE SET NULL,
    is_published BOOLEAN NOT NULL DEFAULT false,
    published_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE blog_posts IS 'Blog articles, news, and dental health tips';
COMMENT ON COLUMN blog_posts.slug IS 'URL-friendly identifier for the post';
COMMENT ON COLUMN blog_posts.excerpt IS 'Short summary for listing pages';

CREATE INDEX idx_blog_posts_published ON blog_posts (is_published, published_at DESC) WHERE is_published = true;
CREATE INDEX idx_blog_posts_slug ON blog_posts (slug);
CREATE INDEX idx_blog_posts_author ON blog_posts (author_id);

-- ============================================================================
-- TABLE: contact_submissions
-- Contact form submissions from the website
-- ============================================================================
CREATE TABLE IF NOT EXISTS contact_submissions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    phone TEXT,
    email TEXT,
    reason TEXT,
    message TEXT NOT NULL,
    is_read BOOLEAN NOT NULL DEFAULT false,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE contact_submissions IS 'Contact form submissions from visitors';

CREATE INDEX idx_contact_submissions_unread ON contact_submissions (is_read, created_at DESC) WHERE is_read = false;
CREATE INDEX idx_contact_submissions_date ON contact_submissions (created_at DESC);

-- ============================================================================
-- TABLE: faq_items
-- Frequently asked questions
-- ============================================================================
CREATE TABLE IF NOT EXISTS faq_items (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    question TEXT NOT NULL,
    answer TEXT NOT NULL,
    category TEXT NOT NULL DEFAULT 'general',
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE faq_items IS 'Frequently asked questions organized by category';

CREATE INDEX idx_faq_items_active ON faq_items (is_active, category, sort_order) WHERE is_active = true;

-- ============================================================================
-- TABLE: settings
-- Key-value store for site configuration
-- ============================================================================
CREATE TABLE IF NOT EXISTS settings (
    key TEXT PRIMARY KEY,
    value JSONB NOT NULL DEFAULT '{}',
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE settings IS 'Site-wide configuration as key-value pairs (JSONB)';

-- ============================================================================
-- TABLE: appointment_requests
-- Online appointment booking requests
-- ============================================================================
CREATE TABLE IF NOT EXISTS appointment_requests (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    phone TEXT NOT NULL,
    email TEXT,
    service_type TEXT,
    preferred_date DATE,
    preferred_time TEXT,
    notes TEXT,
    status TEXT NOT NULL DEFAULT 'pendiente' CHECK (status IN ('pendiente', 'confirmada', 'completada', 'cancelada')),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE appointment_requests IS 'Online appointment booking requests from patients';
COMMENT ON COLUMN appointment_requests.status IS 'pendiente | confirmada | completada | cancelada';

CREATE INDEX idx_appointment_requests_status ON appointment_requests (status, created_at DESC);
CREATE INDEX idx_appointment_requests_date ON appointment_requests (preferred_date) WHERE status IN ('pendiente', 'confirmada');

-- ============================================================================
-- TABLE: referrals
-- Patient referral program
-- ============================================================================
CREATE TABLE IF NOT EXISTS referrals (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    referrer_name TEXT NOT NULL,
    referrer_phone TEXT NOT NULL,
    friend_name TEXT NOT NULL,
    friend_phone TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'pendiente',
    notes TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

COMMENT ON TABLE referrals IS 'Patient referral tracking for referral program';

CREATE INDEX idx_referrals_status ON referrals (status, created_at DESC);

-- ============================================================================
-- TABLE: promotions
-- Active promotions and special offers
-- ============================================================================
CREATE TABLE IF NOT EXISTS promotions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    image_url TEXT,
    promo_code TEXT,
    start_date DATE NOT NULL,
    end_date DATE NOT NULL,
    terms TEXT,
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),

    CONSTRAINT promotions_date_range CHECK (end_date >= start_date)
);

COMMENT ON TABLE promotions IS 'Special offers, promotions, and discount campaigns';
COMMENT ON COLUMN promotions.promo_code IS 'Optional promotional code for tracking';

CREATE INDEX idx_promotions_active_dates ON promotions (is_active, start_date, end_date) WHERE is_active = true;

-- ============================================================================
-- TABLE: page_views (for analytics function)
-- Simple page view counter
-- ============================================================================
CREATE TABLE IF NOT EXISTS page_views (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    page_slug TEXT NOT NULL,
    view_count BIGINT NOT NULL DEFAULT 0,
    last_viewed_at TIMESTAMPTZ NOT NULL DEFAULT now(),

    CONSTRAINT page_views_slug_unique UNIQUE (page_slug)
);

COMMENT ON TABLE page_views IS 'Simple page view analytics counter';

CREATE INDEX idx_page_views_slug ON page_views (page_slug);

-- ============================================================================
-- Trigger: auto-update updated_at columns
-- ============================================================================
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_blog_posts_updated_at
    BEFORE UPDATE ON blog_posts
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER trg_appointment_requests_updated_at
    BEFORE UPDATE ON appointment_requests
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER trg_settings_updated_at
    BEFORE UPDATE ON settings
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();
"}
